const tables = {
  action: "Oracle Monster Action Words",
  descriptor: "Oracle Monster Descriptor Words",
  personality: "Enemy Personality Table",
  goal: "Enemy Goals",
  monsters: "Monsters",
  humanoids: "Humanoids",
  firstNames: "First Names"
};

async function drawFromTable(tableName) {
  const table = game.tables.getName(tableName);

  if (!table) {
    ui.notifications.error(`RollTable "${tableName}" not found.`);
    return null;
  }

  const roll = await table.roll();
  const result = roll.results[0];

  return {
    roll: result.range[0],
    text: result.text
  };
}

function drawCard() {
  const suits = ["Hearts", "Diamonds", "Clubs", "Spades"];
  const ranks = [
    "Ace", "2", "3", "4", "5", "6", "7", "8", "9", "10",
    "Jack", "Queen", "King"
  ];

  const suit = suits[Math.floor(Math.random() * suits.length)];
  const rank = ranks[Math.floor(Math.random() * ranks.length)];

  const color = ["Hearts", "Diamonds"].includes(suit) ? "Red" : "Black";
  const mobType = color === "Red" ? "Humanoids" : "Monsters";
  const isElite = ["Jack", "Queen", "King"].includes(rank);

  let count = Number(rank);
  if (rank === "Ace") count = 1;
  if (isElite) count = 1;

  return {
    rank,
    suit,
    color,
    mobType,
    isElite,
    count
  };
}

// Roll 1d6 for number of mob groups
const mobCountRoll = await new Roll("1d6").evaluate();
const mobCount = mobCountRoll.total;

let content = `
<h2>⚔️ Mobs Created</h2>
<p><strong>Mob Groups Roll:</strong> ${mobCountRoll.total}</p>
`;

for (let i = 1; i <= mobCount; i++) {
  const card = drawCard();

  const creature = card.mobType === "Humanoids"
    ? await drawFromTable(tables.humanoids)
    : await drawFromTable(tables.monsters);

  const eliteName = card.isElite
    ? await drawFromTable(tables.firstNames)
    : null;

  const action = await drawFromTable(tables.action);
  const descriptor = await drawFromTable(tables.descriptor);
  const personality = await drawFromTable(tables.personality);
  const goal = await drawFromTable(tables.goal);

  content += `
    <hr>
    <h3>Mob ${i}</h3>
    <ul>
      <li><strong>Card:</strong> ${card.rank} of ${card.suit}</li>
      <li><strong>Mob Type:</strong> ${card.isElite ? "Elite " : ""}${card.mobType}</li>
      <li><strong>Number Appearing:</strong> ${card.count}</li>
      <li><strong>Creature:</strong> [${creature.roll}] ${creature.text}</li>
      ${card.isElite ? `<li><strong>Elite Name:</strong> [${eliteName.roll}] ${eliteName.text}</li>` : ""}
      <li><strong>Concept:</strong> [${action.roll}] ${action.text} + [${descriptor.roll}] ${descriptor.text}</li>
      <li><strong>Personality:</strong> [${personality.roll}] ${personality.text}</li>
      <li><strong>Goal:</strong> [${goal.roll}] ${goal.text}</li>
    </ul>
  `;
}

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
  content
});
